// Hidden oracle for gh-4115 (fix a7080261) — withheld from the maker.
// A Kubernetes-safe UNDERSCORE env var must override a DASHED gear name.
use toolkit::bootstrap::config::AppConfig;

#[test]
fn oracle_bug1_dashed_gear_env_override_applies() {
    // YAML seeds the dashed gear's priority = 100
    write_cfg("gears: { static-authz-plugin: { config: { priority: 100 } } }");

    temp_env::with_var("APP__GEARS__STATIC_AUTHZ_PLUGIN__CONFIG__PRIORITY", Some("50"), || {
        let config = AppConfig::load_layered(&cfg_path).expect("config load");
        let p = config.gears.get("static-authz-plugin")
            .and_then(|g| g.get("config")).and_then(|c| c.get("priority"))
            .and_then(|p| p.as_i64()).expect("priority");
        assert_eq!(p, 50, "underscore env must override the dashed gear (RED=100)");
    });
}
